#include <stdio.h>
#include <ctype.h>
#include <string.h>
#define MAX_LEN 105
int main(){
    int T; if(scanf("%d",&T)!=1) return 0; getchar(); // consume newline after T
    char line[MAX_LEN];
    for(int tc=0; tc<T; ++tc){
        if(!fgets(line, MAX_LEN, stdin)) line[0]='\0';
        size_t len = strlen(line);
        if(len && line[len-1]=='\n') line[--len]='\0';
        for(size_t i=0;i<len;++i){
            char c=line[i];
            if(i%2==0) c = (char)tolower((unsigned char)c);
            else c = (char)toupper((unsigned char)c);
            putchar(c);
        }
        if(tc<T-1) putchar('\n');
    }
    return 0;
}

