import sys

def transform(s):
    res = []
    for i,ch in enumerate(s):
        if i%2==0:
            res.append(ch.lower())
        else:
            res.append(ch.upper())
    return ''.join(res)

def main():
    data = sys.stdin.read().splitlines()
    if not data:
        return
    T = int(data[0].strip()) if data[0].strip() else 0
    out = []
    for i in range(1, T+1):
        line = data[i] if i < len(data) else ''
        out.append(transform(line))
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    main()

